YANTRAS_DATA = [
    {"id": "sri-yantra", "name": "Sri Yantra", "sanskrit": "Shri Yantra", "description": "The most revered of all yantras, representing the cosmic creation and the union of Shiva and Shakti. Composed of 9 interlocking triangles that surround and radiate from a central bindu point — 4 upward triangles (Shiva/masculine) and 5 downward (Shakti/feminine). The entire cosmos is contained within this sacred form. It has 43 triangles, 24 vertices, and represents the journey from the material world to ultimate enlightenment.", "meaning": "Supreme creation, divine feminine power, abundance, unity of all existence", "deity": "Tripura Sundari / Lalita Devi", "mantra": "Om Shreem Hreem Shreem Kamale Kamalaleyi Praseed Praseed Shreem Hreem Shreem Om Mahalakshmiyei Namaha", "meditation": "Sit in a quiet, dimly lit space. Place the Sri Yantra at eye level. Gaze softly at the central bindu point without straining. Allow your vision to slowly expand outward through the interlocking triangles. The 4 upward triangles represent Shiva (consciousness), the 5 downward represent Shakti (creative energy). As you gaze, feel these energies uniting within your own being. Visualize golden-white light emanating from the bindu, filling each triangle, each lotus petal, each gate. You are traveling from the outer world to the innermost point of creation. Rest in the bindu — the source of all. Chant the mantra 108 times.", "color": "#EF4444", "pattern": "sri-yantra"},
    {"id": "ganesh-yantra", "name": "Ganesh Yantra", "sanskrit": "Ganapati Yantra", "description": "Dedicated to Lord Ganesha, the elephant-headed deity who removes obstacles and bestows new beginnings. This yantra features a central triangle surrounded by lotus petals and geometric gates. Ganesha is always invoked first in any spiritual practice, and his yantra is traditionally the first to be worshipped. The central triangle represents the three gunas (qualities) of nature: sattva, rajas, and tamas.", "meaning": "Obstacle removal, new beginnings, wisdom, success in endeavors", "deity": "Ganesha / Ganapati", "mantra": "Om Gam Ganapataye Namaha", "meditation": "Focus on the central triangle, representing the three aspects of creation — creation, preservation, and transformation. Visualize golden light dissolving all obstacles in your path. See each obstacle as a locked gate, and watch as Lord Ganesha opens them one by one with his wisdom and power. Chant the Ganesha mantra 108 times while gazing at the yantra. Feel the energy of new beginnings flowing through you. This yantra is especially powerful when starting new projects, businesses, or life chapters.", "color": "#FB923C", "pattern": "ganesh-yantra"},
    {"id": "kali-yantra", "name": "Kali Yantra", "sanskrit": "Kalika Yantra", "description": "The yantra of Goddess Kali, the fierce divine mother who destroys ego, illusion, and ignorance. Features five downward-pointing triangles representing the five elements being consumed by transformative fire, surrounded by a circle of flames. Kali represents time itself (Kala) and the relentless transformation of all things. Her yantra is for those ready to surrender the ego and face their deepest fears.", "meaning": "Transformation, liberation from ego, destruction of illusion, fearlessness", "deity": "Kali / Kalika / Mahakali", "mantra": "Om Kreem Kalikaye Namaha", "meditation": "This is an advanced practice. Contemplate the five downward-pointing triangles representing the five elements being dissolved back into pure consciousness. The circle of flames represents the fire of wisdom that burns away ignorance. Gaze at the yantra and ask: What am I holding onto that no longer serves me? Visualize Kali's sword cutting the cords of attachment, fear, and ego. Surrender what must be released. This is not destruction — it is liberation. The darkness of Kali is the darkness of the infinite void from which all creation emerges. Rest in that void.", "color": "#7C3AED", "pattern": "kali-yantra"},
    {"id": "saraswati-yantra", "name": "Saraswati Yantra", "sanskrit": "Sarasvati Yantra", "description": "The yantra of Goddess Saraswati, bestower of knowledge, music, art, wisdom, and eloquent speech. Features a central hexagram (two interlocking triangles) surrounded by lotus petals, representing the union of knowledge and creativity. Saraswati is depicted dressed in white, playing the veena — symbolizing purity of knowledge and the music of the cosmos.", "meaning": "Knowledge, art, music, wisdom, learning, eloquent speech, creative mastery", "deity": "Saraswati / Sarasvati / Vagdevi", "mantra": "Om Aim Saraswatyai Namaha", "meditation": "Focus on the central hexagram where two triangles merge — the upward triangle of knowledge and the downward triangle of creative expression. Visualize white or silver light flowing into your throat chakra and third eye, illuminating the centers of speech and intuition. If you are a student, visualize the texts you study being illuminated with golden light. If you are an artist, visualize your creative channels opening like lotus petals. Chant the mantra before study, exams, creative work, or musical practice. Saraswati's energy flows most powerfully during dawn and dusk.", "color": "#F8FAFC", "pattern": "saraswati-yantra"},
    {"id": "lakshmi-yantra", "name": "Lakshmi Yantra", "sanskrit": "Shri Lakshmi Yantra", "description": "The yantra of Goddess Lakshmi, the embodiment of abundance, prosperity, beauty, and spiritual grace. Features lotus petals radiating from a golden center, representing the eight forms of wealth (Ashta Lakshmi): material wealth, health, knowledge, courage, progeny, food/nourishment, success, and spiritual wealth.", "meaning": "Abundance, prosperity, grace, beauty, all eight forms of wealth", "deity": "Lakshmi / Mahalakshmi", "mantra": "Om Shreem Mahalakshmiyei Namaha", "meditation": "Gaze at the golden center, representing the seed of abundance already present within you. The radiating lotus petals represent the unfolding of prosperity in all eight directions and all eight forms. Visualize golden light filling every aspect of your existence — not just material wealth, but health, knowledge, love, nourishment, courage, spiritual growth, and success. Lakshmi resides where there is cleanliness, gratitude, and generosity. Before practicing, clean your meditation space and offer gratitude for what you already have. The energy of Lakshmi multiplies what you appreciate.", "color": "#FCD34D", "pattern": "lakshmi-yantra"},
    {"id": "durga-yantra", "name": "Durga Yantra", "sanskrit": "Durga Yantra", "description": "The yantra of Goddess Durga, the invincible warrior mother who protects devotees from all harm. A powerful protective shield featuring a star pattern within concentric circles of defense. Durga was created by the combined powers of all the gods to defeat the demon Mahishasura — she represents the concentrated power of divine protection.", "meaning": "Protection, courage, invincible strength, victory over evil, divine motherly protection", "deity": "Durga / Mahishasuramardini", "mantra": "Om Dum Durgaye Namaha", "meditation": "Visualize the yantra as an impenetrable shield of divine light surrounding you. Each point of the star radiates protective energy outward, creating a sphere of invincibility. Feel the fierce, unconditional love of the divine mother — she who will stop at nothing to protect her children. If you face enemies, obstacles, or threatening situations, call upon Durga's protection through this yantra. Visualize her riding her lion, wielding weapons of divine power, standing between you and all harm. Her protection extends to physical, emotional, mental, and spiritual realms.", "color": "#EF4444", "pattern": "durga-yantra"},
    {"id": "shiva-yantra", "name": "Shiva Yantra", "sanskrit": "Mahamrityunjaya Yantra", "description": "The yantra of Lord Shiva in his healing aspect as the Great Conqueror of Death (Mahamrityunjaya). Used for health, longevity, and overcoming the fear of death. The central point represents pure consciousness — Shiva as the witness of all creation and destruction. This is the most powerful healing yantra in the Vedic tradition.", "meaning": "Healing, longevity, liberation from fear of death, immortal consciousness", "deity": "Shiva / Mahadeva / Mrityunjaya", "mantra": "Om Tryambakam Yajamahe Sugandhim Pushtivardhanam Urvarukamiva Bandhanan Mrityor Mukshiya Maamritat", "meditation": "Focus on the central bindu, representing pure consciousness that is beyond birth and death. Feel healing energy spiraling outward through each geometric layer — from the innermost point of awareness to the outermost boundary of your body. This yantra is traditionally used for healing meditations, overcoming serious illness, and for those facing the fear of death or dying. Chant the Mahamrityunjaya mantra 108 times — this is considered the most powerful healing mantra in existence. Visualize amrit (nectar of immortality) flowing from the bindu, healing every cell of your body.", "color": "#3B82F6", "pattern": "shiva-yantra"},
    {"id": "hanuman-yantra", "name": "Hanuman Yantra", "sanskrit": "Hanuman Yantra", "description": "The yantra of Lord Hanuman, the mighty devotee of Rama who embodies supreme devotion, selfless service, courage, and physical strength. Hanuman represents the perfection of devotion — his strength comes entirely from his love for the divine. This yantra protects against black magic, evil spirits, and negative energies.", "meaning": "Devotion, courage, physical strength, protection from negative forces, selfless service", "deity": "Hanuman / Bajrangbali / Maruti", "mantra": "Om Ham Hanumate Namaha", "meditation": "Gaze upon this yantra and invoke the spirit of supreme devotion. Hanuman could move mountains, cross oceans, and face armies — all through the power of his devotion to truth (Rama). Ask yourself: What do I serve with my whole heart? Visualize Hanuman's golden form radiating protective energy, dispelling all fear and negativity. This yantra is especially powerful on Tuesdays and Saturdays. Chant the mantra when facing fear, when needing physical courage, or when black magic or negative energies are suspected.", "color": "#FB923C", "pattern": "hanuman-yantra"},
    {"id": "navgraha-yantra", "name": "Navagraha Yantra", "sanskrit": "Nine Planets Yantra", "description": "A comprehensive yantra representing all nine celestial influences (grahas) in Vedic astrology: Sun, Moon, Mars, Mercury, Jupiter, Venus, Saturn, Rahu, and Ketu. This single yantra balances all planetary energies and neutralizes astrological afflictions in the birth chart.", "meaning": "Planetary harmony, neutralizing astrological afflictions, cosmic balance", "deity": "Nine Planetary Deities", "mantra": "Om Navagraha Devatabyoh Namaha", "meditation": "This yantra addresses the influence of all nine planets simultaneously. Place it facing east. Each section of the yantra corresponds to a specific planet and its energy. Meditate on the center (Sun/Surya) and gradually expand awareness to include all nine planetary forces. Visualize each planet sending its balanced, beneficent energy to you. This is especially useful during planetary transits, Saturn returns, or when facing challenges attributed to planetary positions in your birth chart. A comprehensive remedy that covers all astrological bases.", "color": "#F59E0B", "pattern": "navgraha-yantra"},
]
